SELECT id AS ticketId, ticket_no AS ticketNo, user_id AS userId, title, status, created_at AS createdAt, updated_at AS updatedAt FROM ticket WHERE user_id = #{userId} AND is_deleted = 0
AND status = #{status}
ORDER BY created_at DESC, id DESC LIMIT #{pageSize} OFFSET #{offset}

